  ('pukao-77f8735d-moex-00051', 'pukao-77f8735d', 'pukao-77f8735d-moex-113-85716566', 'sub-pukao-77f8735d-03', NULL, 'single_choice', '依據衛生福利部出版的長期照顧十年計畫2.0（核定本），對於民眾長期照顧的需求，通常以三類 功能損傷程度做為評估的依據，請問下列那一個選項的評估模式不包含在內？', '["日常生活活動功能（activitiesofdailyliving,ADLs）", "工具性日常生活活動功能（instrumentalactivitiesofdailyliving,IADLs）", "心智功能", "客觀結構式臨床測驗（objectivestructuredclinicalexamination,OSCE）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:04+00:00", "source_pdf_sha1": "ac02d8f0ebe9", "answer_pdf_sha1": "bc389906415c", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "429", "s": "2105", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "衛生行政學概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "衛生行政"}'::jsonb, NULL),
  ('pukao-77f8735d-moex-00052', 'pukao-77f8735d', 'pukao-77f8735d-moex-113-85716566', 'sub-pukao-77f8735d-03', NULL, 'single_choice', 'SWOT是行政管理領域常見的的應用工具，下列那一個選項的答案是這個方法最適合使用的 時機？', '["環境分析階段", "計畫建構階段", "計畫執行階段", "計畫評估階段"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:04+00:00", "source_pdf_sha1": "ac02d8f0ebe9", "answer_pdf_sha1": "bc389906415c", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "429", "s": "2105", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "衛生行政學概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "衛生行政"}'::jsonb, NULL),
  ('pukao-77f8735d-moex-00053', 'pukao-77f8735d', 'pukao-77f8735d-moex-113-85716566', 'sub-pukao-77f8735d-03', NULL, 'single_choice', '組織財務管理的主要目的在將有限的資源產生最大的效益，財務管理的過程必須借重財務報表以 獲取重要的管理訊息。下列那一個選項的財務報表製作是以特定的時間點為依據，彙整相關的會 計產出之資訊而成？', '["資產負債表", "收支餘絀表", "現金流量表", "權益變動表"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:04+00:00", "source_pdf_sha1": "ac02d8f0ebe9", "answer_pdf_sha1": "bc389906415c", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "429", "s": "2105", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "衛生行政學概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "衛生行政"}'::jsonb, NULL),
  ('pukao-77f8735d-moex-00054', 'pukao-77f8735d', 'pukao-77f8735d-moex-113-85716566', 'sub-pukao-77f8735d-03', NULL, 'single_choice', '依據我國111年死因統計結果分析的資訊，目前我國自殺死亡率最高的年齡層是下列那一個 選項？', '["15-24歲", "25-44歲", "45-64歲", "65歲以上"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:04+00:00", "source_pdf_sha1": "ac02d8f0ebe9", "answer_pdf_sha1": "bc389906415c", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "429", "s": "2105", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "衛生行政學概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "衛生行政"}'::jsonb, NULL),
  ('pukao-77f8735d-moex-00055', 'pukao-77f8735d', 'pukao-77f8735d-moex-113-85716566', 'sub-pukao-77f8735d-03', NULL, 'single_choice', '傳染病偵測系統（surveillancesystem）應有多元化的特質，以期透過各自的優缺點來截長補短。 其中能夠避免判斷錯誤的發生是下列那一個特質的優點？', '["敏感度（sensitivity）", "時效性（timeliness）", "代表性（representativeness）", "特異性（specificity）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:04+00:00", "source_pdf_sha1": "ac02d8f0ebe9", "answer_pdf_sha1": "bc389906415c", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "429", "s": "2105", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "衛生行政學概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "衛生行政"}'::jsonb, NULL),
  ('pukao-77f8735d-moex-00056', 'pukao-77f8735d', 'pukao-77f8735d-moex-113-85716566', 'sub-pukao-77f8735d-03', NULL, 'single_choice', '健康傳播是指健康訊息經過特殊處理後，經由有效的管道傳遞給社會大眾，影響他們實行健康的 生活方式以提升健康。在學理上，健康傳播的理論可以從不同層次（個人、社區、社會文化等） 的角度加以探討，下列那一個選項的健康傳播理論是屬於社會文化層次的角度？', '["創新擴散理論（diffusionofinnovationtheory）", "涵化理論（cultivationtheory）", "社會學習理論（sociallearningtheory）", "知溝理論（knowledgegaptheory）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:04+00:00", "source_pdf_sha1": "ac02d8f0ebe9", "answer_pdf_sha1": "bc389906415c", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "429", "s": "2105", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "衛生行政學概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "衛生行政"}'::jsonb, NULL),
  ('pukao-77f8735d-moex-00057', 'pukao-77f8735d', 'pukao-77f8735d-moex-113-85716566', 'sub-pukao-77f8735d-03', NULL, 'single_choice', '世界衛生組織於2000年提出健康照護體系的評估架構，其中「回應民眾對於與健康無關的期望」 是架構中的三大重要目標之一。請問下列那一個選項不是回應民眾對於與健康無關期望的涵蓋 內容？', '["個人的尊重", "財務負擔的公平性", "就醫選擇的自由", "社會支持網絡的可近性"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:04+00:00", "source_pdf_sha1": "ac02d8f0ebe9", "answer_pdf_sha1": "bc389906415c", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "429", "s": "2105", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "衛生行政學概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "衛生行政"}'::jsonb, NULL),
  ('pukao-77f8735d-moex-00058', 'pukao-77f8735d', 'pukao-77f8735d-moex-113-85716566', 'sub-pukao-77f8735d-03', NULL, 'single_choice', '公共衛生方案的經濟評估有著不同的方法，下列選項當中那一個是將投入與產出皆轉化為貨幣價 值後加以衡量比較的方法？', '["cost-effectivenessanalysis（CEA）", "cost-minimizationanalysis（CMA）", "cost-benefitanalysis（CBA）", "cost-utilityanalysis（CUA）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:04+00:00", "source_pdf_sha1": "ac02d8f0ebe9", "answer_pdf_sha1": "bc389906415c", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "429", "s": "2105", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "衛生行政學概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "衛生行政"}'::jsonb, NULL),
  ('pukao-77f8735d-moex-00059', 'pukao-77f8735d', 'pukao-77f8735d-moex-113-85716566', 'sub-pukao-77f8735d-03', NULL, 'single_choice', '經濟評估的方法，基本上可用來比較兩個或兩個以上的方案，在解決某一個問題時（如疾病的預 防）所投入的成本與可以得到的成果。其中在成本的考量上，可以將成本區分為直接成本與間接 成本，若以疫苗注射為例，請問下列那一個選項是屬於間接成本？', '["接受疫苗注射所損失的工作所得", "疫苗施打所花費的場地租金與工作人員薪資", "為了施打疫苗所花費的交通費用", "疫苗生產的成本"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:04+00:00", "source_pdf_sha1": "ac02d8f0ebe9", "answer_pdf_sha1": "bc389906415c", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "429", "s": "2105", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "衛生行政學概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "衛生行政"}'::jsonb, NULL)
